"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconArmchair,
  IconArrowRight,
  IconBrush,
  IconCash,
  IconCheck,
  IconChefHat,
  IconClock,
  IconFlame,
  IconHourglass,
  IconReceipt2,
  IconToolsKitchen2,
  IconUser,
  IconUsers,
} from "@tabler/icons-react";

import {
  Badge,
  Banner,
  Button,
  Card,
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerFooter,
  DrawerHeader,
  DrawerTitle,
  HStack,
  Icon,
  KanbanBoard,
  type KanbanColumn,
  Meter,
  MetadataList,
  Separator,
  StatGroup,
  type StatisticProps,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Tag,
  VStack,
  formatCurrency,
} from "@gunjo/ui";

import {
  FLOOR_TABLES,
  KITCHEN_TICKETS,
  TABLE_STATE_LABEL,
  TICKET_STAGE_LABEL,
  TICKET_STAGE_ORDER,
  type FloorTable,
  type KitchenTicket,
  type TableState,
  type TicketStage,
  formatMinutes,
  isLongStay,
  isTicketDelayed,
} from "./data";

// ── 状態 → 見た目（色だけに頼らずアイコン＋ラベルで二重符号化） ──────────

const STATE_BADGE: Record<
  TableState,
  { variant: React.ComponentProps<typeof Badge>["variant"]; icon: React.ReactNode }
> = {
  vacant: { variant: "outline", icon: <IconArmchair /> },
  seated: { variant: "info", icon: <IconUser /> },
  ordering: { variant: "info", icon: <IconReceipt2 /> },
  dining: { variant: "success", icon: <IconToolsKitchen2 /> },
  check: { variant: "warning", icon: <IconCash /> },
  cleaning: { variant: "default", icon: <IconBrush /> },
};

const STAGE_TONE: Record<TicketStage, KanbanColumn["tone"]> = {
  received: "muted",
  cooking: "warning",
  ready: "success",
  served: "default",
};

const STAGE_NEXT_LABEL: Record<TicketStage, string | null> = {
  received: "調理開始",
  cooking: "できあがり",
  ready: "提供済にする",
  served: null,
};

// 卓カードの枠線色を状態で（要対応を一目で）。
const TILE_RING: Record<TableState, string> = {
  vacant: "border-border bg-muted/20",
  seated: "border-info-border",
  ordering: "border-info-border",
  dining: "border-border",
  check: "border-warning-border bg-warning-subtle/40",
  cleaning: "border-border bg-muted/30",
};

export default function RestaurantFloorPage() {
  const [tables, setTables] = React.useState<FloorTable[]>(FLOOR_TABLES);
  const [tickets, setTickets] = React.useState<KitchenTicket[]>(KITCHEN_TICKETS);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);

  const selected = tables.find((t) => t.id === selectedId) ?? null;
  const selectedTickets = tickets.filter((t) => t.tableId === selectedId);

  // ── 集計（要対応・サマリ） ────────────────────────────────
  const occupied = tables.filter((t) => t.state !== "vacant" && t.state !== "cleaning");
  const seatsTotal = tables.reduce((s, t) => s + t.seats, 0);
  const guestsNow = tables.reduce((s, t) => s + t.guests, 0);
  const checkWaiting = tables.filter((t) => t.state === "check");
  const longStays = tables.filter(isLongStay);
  const delayed = tickets.filter(isTicketDelayed);
  const cookingQueue = tickets.filter(
    (t) => t.stage === "received" || t.stage === "cooking"
  );
  const readyToServe = tickets.filter((t) => t.stage === "ready");
  const avgStay =
    occupied.length > 0
      ? Math.round(
          occupied.reduce((s, t) => s + t.seatedMinutes, 0) / occupied.length
        )
      : 0;
  const salesToday = 284600 + tables.reduce((s, t) => s + t.total, 0);

  const metrics: StatisticProps[] = [
    {
      label: "稼働卓 / 全卓",
      value: `${occupied.length} / ${tables.length}`,
      hint: `客数 ${guestsNow}名・${seatsTotal}席`,
    },
    {
      label: "満席率",
      value: `${Math.round((occupied.length / tables.length) * 100)}%`,
      trend: "up",
      change: "ピーク帯",
      tone: "neutral",
    },
    {
      label: "平均滞在",
      value: formatMinutes(avgStay),
      hint: "稼働卓の平均",
    },
    {
      label: "調理待ち",
      value: `${cookingQueue.length}件`,
      hint: `提供待ち ${readyToServe.length}件`,
      tone: cookingQueue.length > 4 ? "negative" : "neutral",
    },
    {
      label: "提供遅延",
      value: `${delayed.length}件`,
      trend: delayed.length > 0 ? "down" : "flat",
      tone: delayed.length > 0 ? "negative" : "neutral",
      hint: delayed.length > 0 ? "目標時間超過" : "遅延なし",
    },
    {
      label: "本日売上",
      value: formatCurrency(salesToday),
      trend: "up",
      change: "+12.4%",
      tone: "positive",
      hint: "前週同曜比",
    },
  ];

  // ── 操作 ────────────────────────────────────────────────
  function advanceTicket(id: string) {
    setTickets((prev) =>
      prev.map((t) => {
        if (t.id !== id) return t;
        const i = TICKET_STAGE_ORDER.indexOf(t.stage);
        const next = TICKET_STAGE_ORDER[Math.min(i + 1, TICKET_STAGE_ORDER.length - 1)];
        return { ...t, stage: next };
      })
    );
  }

  function setTableState(id: string, state: TableState) {
    setTables((prev) =>
      prev.map((t) =>
        t.id === id
          ? {
              ...t,
              state,
              ...(state === "vacant"
                ? { guests: 0, seatedMinutes: 0, total: 0, server: "—" as const }
                : {}),
            }
          : t
      )
    );
  }

  const kanbanColumns: KanbanColumn[] = TICKET_STAGE_ORDER.map((stage) => ({
    id: stage,
    title: TICKET_STAGE_LABEL[stage],
    tone: STAGE_TONE[stage],
  }));

  return (
    <main className="mx-auto w-full max-w-[1400px] px-4 py-5 sm:px-6">
      {/* ヘッダー */}
      <header className="mb-4 flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-xl font-bold tracking-tight sm:text-2xl">
            ホール運営ボード
          </h1>
          <p className="text-sm text-muted-foreground">
            ビストロ・グンジョー 神南店 ・ ディナー営業 19:42
          </p>
        </div>
        <HStack gap={2} align="center" className="flex-wrap">
          <Badge variant="success" icon={<IconUsers />}>
            客数 {guestsNow}名
          </Badge>
          <Badge variant="outline" icon={<IconChefHat />}>
            キッチン 3名
          </Badge>
        </HStack>
      </header>

      {/* 要対応（最優先の通知） */}
      <VStack gap={2} className="mb-5" role="region" aria-label="要対応">
        {delayed.length > 0 && (
          <Banner
            variant="destructive"
            icon={<IconFlame className="h-4 w-4" />}
            action={
              <span className="hidden text-xs font-medium sm:inline">
                {delayed.map((t) => t.tableId).join("・")}
              </span>
            }
          >
            提供遅延 {delayed.length}件 — 目標時間を超過しています
          </Banner>
        )}
        {checkWaiting.length > 0 && (
          <Banner
            variant="warning"
            icon={<IconCash className="h-4 w-4" />}
            action={
              <span className="hidden text-xs font-medium sm:inline">
                {checkWaiting.map((t) => t.label).join("・")}
              </span>
            }
          >
            会計待ち {checkWaiting.length}卓 — レジへ案内してください
          </Banner>
        )}
        {longStays.length > 0 && (
          <Banner variant="info" icon={<IconHourglass className="h-4 w-4" />}>
            長時間滞在 {longStays.length}卓（120分超）—{" "}
            {longStays.map((t) => t.label).join("・")}
          </Banner>
        )}
      </VStack>

      {/* サマリ・メトリクス */}
      <section aria-label="サマリ指標" className="mb-6">
        <StatGroup items={metrics} cols={{ base: 2, md: 3, lg: 6 }} />
      </section>

      {/* フロア / キッチンを切替（モバイルは縦積みになりがちなので分離） */}
      <Tabs defaultValue="floor" className="w-full">
        <TabsList className="mb-4">
          <TabsTrigger value="floor">
            <Icon icon={IconArmchair} size="sm" className="mr-1.5" />
            フロア状況
          </TabsTrigger>
          <TabsTrigger value="kitchen">
            <Icon icon={IconToolsKitchen2} size="sm" className="mr-1.5" />
            キッチン（KDS）
            {readyToServe.length > 0 && (
              <Badge variant="success" className="ml-2">
                提供待ち {readyToServe.length}
              </Badge>
            )}
          </TabsTrigger>
        </TabsList>

        {/* ── フロア状況：卓ステータスのタイル ── */}
        <TabsContent value="floor">
          <ul
            className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6"
            aria-label="卓一覧"
          >
            {tables.map((table) => {
              const badge = STATE_BADGE[table.state];
              const longStay = isLongStay(table);
              const tableDelayed = tickets.some(
                (t) => t.tableId === table.id && isTicketDelayed(t)
              );
              return (
                <li key={table.id}>
                  <Card
                    className={`h-full cursor-pointer p-3 transition-colors hover:border-ring/60 ${TILE_RING[table.state]}`}
                    role="button"
                    tabIndex={0}
                    aria-label={`卓 ${table.label}、${TABLE_STATE_LABEL[table.state]}、${table.guests}名`}
                    onClick={() => setSelectedId(table.id)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        setSelectedId(table.id);
                      }
                    }}
                  >
                    <div className="flex items-center justify-between">
                      <span className="text-base font-bold tracking-tight">
                        {table.label}
                      </span>
                      <Badge variant={badge.variant} icon={badge.icon}>
                        {TABLE_STATE_LABEL[table.state]}
                      </Badge>
                    </div>

                    <div className="mt-2 flex items-center gap-1 text-xs text-muted-foreground">
                      <Icon icon={IconUsers} size="xs" />
                      <span className="tabular-nums">
                        {table.guests}/{table.seats}名
                      </span>
                      {table.state !== "vacant" && table.state !== "cleaning" && (
                        <>
                          <span aria-hidden>・</span>
                          <Icon icon={IconClock} size="xs" />
                          <span className="tabular-nums">
                            {formatMinutes(table.seatedMinutes)}
                          </span>
                        </>
                      )}
                    </div>

                    {table.state !== "vacant" && table.state !== "cleaning" ? (
                      <div className="mt-2 flex items-center justify-between gap-2">
                        <span className="truncate text-xs text-muted-foreground">
                          <Icon icon={IconUser} size="xs" className="mr-0.5 inline" />
                          {table.server}
                        </span>
                        <span className="text-sm font-semibold tabular-nums">
                          {table.total > 0 ? formatCurrency(table.total) : "—"}
                        </span>
                      </div>
                    ) : (
                      <div className="mt-2 text-xs text-muted-foreground">
                        {table.state === "cleaning" ? "セット中" : "ご案内可"}
                      </div>
                    )}

                    {(longStay || tableDelayed) && (
                      <div className="mt-2 flex flex-wrap gap-1">
                        {tableDelayed && (
                          <Tag variant="destructive" size="sm">
                            <IconFlame className="h-3 w-3" />
                            提供遅延
                          </Tag>
                        )}
                        {longStay && (
                          <Tag variant="outline" size="sm">
                            <IconHourglass className="h-3 w-3" />
                            長居
                          </Tag>
                        )}
                      </div>
                    )}
                  </Card>
                </li>
              );
            })}
          </ul>
        </TabsContent>

        {/* ── キッチン（KDS）：注文の調理ステージ ── */}
        <TabsContent value="kitchen">
          <KanbanBoard
            columns={kanbanColumns}
            items={tickets}
            getItemId={(t) => t.id}
            getColumnId={(t) => t.stage}
            columnWidth={272}
            emptyLabel="伝票なし"
            renderCard={(t) => <KitchenTicketCard ticket={t} onAdvance={advanceTicket} />}
          />
        </TabsContent>
      </Tabs>

      {/* 卓 detail ドリルイン */}
      <Drawer
        open={selectedId != null}
        onOpenChange={(open) => !open && setSelectedId(null)}
      >
        <DrawerContent side="right" className="w-[420px] max-w-[calc(100%-1.5rem)]">
          {selected && (
            <TableDetail
              table={selected}
              tickets={selectedTickets}
              onSetState={(s) => setTableState(selected.id, s)}
            />
          )}
        </DrawerContent>
      </Drawer>
    </main>
  );
}

// ── KDS チケットカード（KanbanBoard の renderCard） ────────────────

function KitchenTicketCard({
  ticket,
  onAdvance,
}: {
  ticket: KitchenTicket;
  onAdvance: (id: string) => void;
}) {
  const delayed = isTicketDelayed(ticket);
  const nextLabel = STAGE_NEXT_LABEL[ticket.stage];
  const qtyTotal = ticket.items.reduce((s, i) => s + i.qty, 0);

  return (
    <VStack gap={2}>
      <div className="flex items-center justify-between">
        <span className="text-sm font-bold tracking-tight">{ticket.tableId}</span>
        <Badge
          variant={delayed ? "destructive" : "outline"}
          icon={delayed ? <IconFlame /> : <IconClock />}
        >
          {ticket.elapsedMinutes}分
        </Badge>
      </div>

      <Meter
        value={ticket.elapsedMinutes}
        max={ticket.targetMinutes}
        size="inline"
        unit="分"
        label={`${ticket.tableId} 経過時間`}
        tone={delayed ? "destructive" : undefined}
        showValue={false}
      />

      <ul className="space-y-0.5 text-xs text-foreground">
        {ticket.items.map((item, i) => (
          <li key={i} className="flex items-start justify-between gap-2">
            <span className="min-w-0">
              <span className="text-muted-foreground">[{item.course}]</span>{" "}
              {item.name}
            </span>
            <span className="shrink-0 tabular-nums text-muted-foreground">
              ×{item.qty}
            </span>
          </li>
        ))}
      </ul>

      {nextLabel ? (
        <Button
          size="sm"
          variant={ticket.stage === "ready" ? "default" : "outline"}
          className="mt-1 w-full"
          onClick={(e) => {
            e.stopPropagation();
            onAdvance(ticket.id);
          }}
        >
          {ticket.stage === "ready" ? (
            <IconCheck className="mr-1 h-3.5 w-3.5" />
          ) : (
            <IconArrowRight className="mr-1 h-3.5 w-3.5" />
          )}
          {nextLabel}
        </Button>
      ) : (
        <div className="mt-1 flex items-center justify-center gap-1 text-xs text-muted-foreground">
          <IconCheck className="h-3.5 w-3.5" />
          提供完了（{qtyTotal}品）
        </div>
      )}
    </VStack>
  );
}

// ── 卓 detail（Drawer 中身） ──────────────────────────────────────

const NEXT_STATES: { state: TableState; label: string; primary?: boolean }[] = [
  { state: "seated", label: "案内する" },
  { state: "ordering", label: "オーダー中" },
  { state: "dining", label: "食事中" },
  { state: "check", label: "会計へ", primary: true },
  { state: "cleaning", label: "下げ・清掃" },
  { state: "vacant", label: "空席に戻す" },
];

function TableDetail({
  table,
  tickets,
  onSetState,
}: {
  table: FloorTable;
  tickets: KitchenTicket[];
  onSetState: (s: TableState) => void;
}) {
  const lines = tickets.flatMap((t) => t.items);
  const subtotal = lines.reduce((s, l) => s + l.price * l.qty, 0);

  const meta = [
    { label: "状態", value: TABLE_STATE_LABEL[table.state] },
    { label: "人数", value: `${table.guests} / ${table.seats}名` },
    { label: "滞在時間", value: formatMinutes(table.seatedMinutes) },
    { label: "担当", value: table.server },
    { label: "伝票合計", value: formatCurrency(table.total || subtotal) },
  ];

  return (
    <>
      <DrawerHeader className="border-b">
        <div className="flex items-center justify-between">
          <DrawerTitle className="text-lg">卓 {table.label}</DrawerTitle>
          <Badge
            variant={STATE_BADGE[table.state].variant}
            icon={STATE_BADGE[table.state].icon}
          >
            {TABLE_STATE_LABEL[table.state]}
          </Badge>
        </div>
        <DrawerDescription>
          {table.note ?? `担当 ${table.server} ・ ${table.guests}名様`}
        </DrawerDescription>
      </DrawerHeader>

      <div className="flex-1 overflow-y-auto p-4">
        <MetadataList items={meta} variant="compact" />

        <Separator className="my-4" />

        <h3 className="mb-2 text-sm font-semibold">注文明細</h3>
        {lines.length > 0 ? (
          <ul className="space-y-1.5">
            {lines.map((l, i) => (
              <li
                key={i}
                className="flex items-start justify-between gap-3 text-sm"
              >
                <span className="min-w-0">
                  <span className="text-xs text-muted-foreground">[{l.course}]</span>{" "}
                  {l.name}{" "}
                  <span className="tabular-nums text-muted-foreground">
                    ×{l.qty}
                  </span>
                </span>
                <span className="shrink-0 tabular-nums">
                  {formatCurrency(l.price * l.qty)}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p className="rounded-md border border-dashed p-3 text-center text-sm text-muted-foreground">
            未オーダー
          </p>
        )}

        {lines.length > 0 && (
          <div className="mt-3 flex items-center justify-between border-t pt-3 text-sm font-semibold">
            <span>小計</span>
            <span className="tabular-nums">{formatCurrency(subtotal)}</span>
          </div>
        )}

        <Separator className="my-4" />

        <h3 className="mb-2 text-sm font-semibold">状態を更新</h3>
        <div className="grid grid-cols-2 gap-2" role="group" aria-label="卓状態の更新">
          {NEXT_STATES.map((opt) => (
            <Button
              key={opt.state}
              variant={
                table.state === opt.state
                  ? "default"
                  : opt.primary
                    ? "outline"
                    : "ghost"
              }
              size="sm"
              disabled={table.state === opt.state}
              onClick={() => onSetState(opt.state)}
            >
              {opt.label}
            </Button>
          ))}
        </div>
      </div>

      <DrawerFooter className="border-t">
        <DrawerClose asChild>
          <Button variant="outline">閉じる</Button>
        </DrawerClose>
        <Button>
          <IconReceipt2 className="mr-1 h-4 w-4" />
          会計を開く
        </Button>
      </DrawerFooter>
    </>
  );
}

// ホール運営 / KDS — ドメイン型とシード（本日ディナー営業のスナップショット）。
// 営業の「いま」を切り取った状態。経過時間は basis 時刻からの差分で算出する。

export type TableState =
  | "vacant" // 空席
  | "seated" // 着席（案内済）
  | "ordering" // オーダー中
  | "dining" // 食事中
  | "check" // 会計待ち
  | "cleaning"; // 下げ・清掃中

export const TABLE_STATE_LABEL: Record<TableState, string> = {
  vacant: "空席",
  seated: "案内済",
  ordering: "オーダー中",
  dining: "食事中",
  check: "会計待ち",
  cleaning: "清掃中",
};

export type ServerName = "高橋" | "佐々木" | "山本" | "—";

export interface FloorTable {
  /** 卓番（例: "T2", "個室A"） */
  id: string;
  label: string;
  /** 席数（卓の最大） */
  seats: number;
  state: TableState;
  /** 着席人数（空席なら 0） */
  guests: number;
  /** 着席時刻からの経過（分）。空席は 0。 */
  seatedMinutes: number;
  server: ServerName;
  /** 現在の伝票合計（税込, 円）。 */
  total: number;
  /** 直近の注文からの提供遅延フラグ用メモ（任意）。 */
  note?: string;
}

export type Course = "前菜" | "メイン" | "パスタ" | "デザート" | "ドリンク";

export interface OrderLine {
  name: string;
  course: Course;
  qty: number;
  price: number;
}

export type TicketStage =
  | "received" // 受付
  | "cooking" // 調理中
  | "ready" // 提供待ち（できあがり）
  | "served"; // 提供済

export const TICKET_STAGE_LABEL: Record<TicketStage, string> = {
  received: "受付",
  cooking: "調理中",
  ready: "提供待ち",
  served: "提供済",
};

export const TICKET_STAGE_ORDER: TicketStage[] = [
  "received",
  "cooking",
  "ready",
  "served",
];

export interface KitchenTicket {
  id: string;
  tableId: string;
  /** この伝票の品目。 */
  items: OrderLine[];
  stage: TicketStage;
  /** 受付からの経過（分）。 */
  elapsedMinutes: number;
  /** 目標提供時間（分）。これを超えると提供遅延。 */
  targetMinutes: number;
}

// ── シードデータ（本日 19:42 時点のディナー営業） ─────────────────────

export const FLOOR_TABLES: FloorTable[] = [
  { id: "T1", label: "T1", seats: 2, state: "dining", guests: 2, seatedMinutes: 48, server: "高橋", total: 8400 },
  { id: "T2", label: "T2", seats: 2, state: "check", guests: 2, seatedMinutes: 96, server: "高橋", total: 12600, note: "デザート提供済・伝票出力済" },
  { id: "T3", label: "T3", seats: 4, state: "ordering", guests: 3, seatedMinutes: 12, server: "佐々木", total: 0 },
