/** 伝票が提供遅延か（目標超過 かつ 未提供）。 */
export function isTicketDelayed(t: KitchenTicket): boolean {
  return t.elapsedMinutes > t.targetMinutes && t.stage !== "served";
}

/** 滞在が長時間か（食事中で 120 分超）。 */
export function isLongStay(t: FloorTable): boolean {
  return t.state === "dining" && t.seatedMinutes >= 120;
}

/** 経過分 → "1時間24分" / "48分" 表記。 */
export function formatMinutes(min: number): string {
  if (min <= 0) return "—";
  const h = Math.floor(min / 60);
  const m = min % 60;
  return h > 0 ? `${h}時間${m}分` : `${m}分`;
}
